defaultText:
{{(() => {
    const name = GetOrderDetails.data[0]?.dropoff_name || '';
    const street = GetOrderDetails.data[0]?.dropoff_street || '';
    return street || name;
  })()}}

onTextChanged:
{{
    (() => {
      // Clear existing timeout
      clearInterval(appsmith.store.dropoffGeoTimeout);

      if (DropoffAddressInput.text && DropoffAddressInput.text.length > 3) {
        // Create new timeout
        const timeoutId = setInterval(() => {
          GeocodeDropoffAddress.run().then(() => {
            if (GeocodeDropoffAddress.data?.length > 0) {
              LocationManager.updateDropoffFromGeocode();
            }
          });
          // Clear after running once
          clearInterval(appsmith.store.dropoffGeoTimeout);
        }, 1500);

        // Store timeout ID
        storeValue('dropoffGeoTimeout', timeoutId);
      }
    })()
  }}
